snippets.C0644:
-- Caso: Búsqueda binaria (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0644
-- Entrada: TEMPORARY TABLE tmp_arr(pos INT PRIMARY KEY, val BIGINT) con pos 0..n-1
DELIMITER $$
CREATE PROCEDURE sp_solve_c0644(IN p_target BIGINT, OUT p_out INT)
BEGIN
  DECLARE v_lo INT DEFAULT 0;
  DECLARE v_hi INT;
  DECLARE v_mid INT;
  DECLARE v_val BIGINT;

  SELECT MAX(pos) INTO v_hi FROM tmp_arr;
  SET p_out = -1;

  loop1: WHILE v_lo <= v_hi DO
    SET v_mid = FLOOR((v_lo + v_hi) / 2);
    SELECT val INTO v_val FROM tmp_arr WHERE pos = v_mid;

    IF v_val = p_target THEN
      SET p_out = v_mid;
      LEAVE loop1;
    END IF;

    IF v_val < p_target THEN
      SET v_lo = v_mid + 1;
    ELSE
      SET v_hi = v_mid - 1;
    END IF;
  END WHILE;
END$$
DELIMITER ;

-- Demo
CREATE TEMPORARY TABLE tmp_arr(pos INT PRIMARY KEY, val BIGINT);
-- INSERT INTO tmp_arr VALUES (0,10),(1,20),(2,30);
SET @out = NULL;
CALL sp_solve_c0644(20, @out);
SELECT @out AS idx;

