-- Caso: Validar brackets (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0645
DELIMITER $$
CREATE PROCEDURE sp_solve_c0645(IN p_s TEXT, OUT p_out TINYINT)
BEGIN
  DECLARE v_stack TEXT DEFAULT '';
  DECLARE v_i INT DEFAULT 1;
  DECLARE v_n INT;
  DECLARE v_ch CHAR(1);
  DECLARE v_top CHAR(1);

  SET v_n = CHAR_LENGTH(p_s);
  SET p_out = 1;

  loop1: WHILE v_i <= v_n DO
    SET v_ch = SUBSTRING(p_s, v_i, 1);

    IF v_ch IN ('(', '[', '{') THEN
      SET v_stack = CONCAT(v_stack, v_ch);
    ELSEIF v_ch IN (')', ']', '}') THEN
      IF CHAR_LENGTH(v_stack) = 0 THEN
        SET p_out = 0;
        LEAVE loop1;
      END IF;

      SET v_top = SUBSTRING(v_stack, CHAR_LENGTH(v_stack), 1);
      SET v_stack = SUBSTRING(v_stack, 1, CHAR_LENGTH(v_stack) - 1);

      IF (v_top='(' AND v_ch<>')') OR (v_top='[' AND v_ch<>']') OR (v_top='{' AND v_ch<>'}') THEN
        SET p_out = 0;
        LEAVE loop1;
      END IF;
    END IF;

    SET v_i = v_i + 1;
  END WHILE;

  IF p_out=1 AND CHAR_LENGTH(v_stack)<>0 THEN
    SET p_out = 0;
  END IF;
END$$
DELIMITER ;

